class WebSocketConnection:
    def __init__(self, client_socket, addr):
        self.socket = client_socket
        self.addr = addr
        self.connected = False
        
    def send_frame(self, data, opcode=0x01):
        if isinstance(data, str):
            data = data.encode('utf-8')
        
        length = len(data)
        frame = bytearray()
        frame.append(0x80 | opcode)
        
        if length < 126:
            frame.append(length)
        elif length < 65536:
            frame.append(126)
            frame.extend(length.to_bytes(2, 'big'))
        else:
            frame.append(127)
            frame.extend(length.to_bytes(8, 'big'))
        
        frame.extend(data)
        
        try:
            self.socket.send(frame)
            return True
        except:
            return False
    
    def receive_frame(self):
        try:
            header = self.socket.recv(2)
            if len(header) < 2:
                return None, None
            
            opcode = header[0] & 0x0F
            masked = header[1] & 0x80
            payload_length = header[1] & 0x7F
            
            if payload_length == 126:
                length_data = self.socket.recv(2)
                payload_length = int.from_bytes(length_data, 'big')
            elif payload_length == 127:
                length_data = self.socket.recv(8)
                payload_length = int.from_bytes(length_data, 'big')
            
            if payload_length > 65536:
                return None, None
            
            mask_key = None
            if masked:
                mask_key = self.socket.recv(4)
            
            payload = bytearray()
            while len(payload) < payload_length:
                chunk = self.socket.recv(min(1024, payload_length - len(payload)))
                if not chunk:
                    break
                payload.extend(chunk)
            
            if masked and mask_key:
                for i in range(len(payload)):
                    payload[i] ^= mask_key[i % 4]
            
            return opcode, bytes(payload)
        except:
            return None, None
    
    def close(self):
        try:
            self.send_frame(b'', 0x08)
            self.socket.close()
        except:
            pass
        self.connected = False

class WebSocketServer:
    def __init__(self, port=80, max_connections=5):
        self.port = port
        self.max_connections = max_connections
        self.clients = []
        self.server_socket = None
        self.command_handlers = {}
        self.running = False
        
    def register_handler(self, action, handler):
        self.command_handlers[action] = handler
    
    def _generate_accept_key(self, key):
        magic_string = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
        sha1 = hashlib.sha1(key.encode() + magic_string.encode())
        return binascii.b2a_base64(sha1.digest()).decode().strip()
    
    def _handle_handshake(self, client_socket):
        try:
            request = client_socket.recv(1024).decode('utf-8')
            
            if 'Upgrade: websocket' not in request:
                client_socket.close()
                return None
            
            lines = request.split('\r\n')
            headers = {}
            for line in lines[1:]:
                if ':' in line:
                    key, value = line.split(':', 1)
                    headers[key.strip()] = value.strip()
            
            if 'Sec-WebSocket-Key' not in headers:
                client_socket.close()
                return None
            
            ws_key = headers['Sec-WebSocket-Key']
            accept_key = self._generate_accept_key(ws_key)
            
            response = (
                "HTTP/1.1 101 Switching Protocols\r\n"
                "Upgrade: websocket\r\n"
                "Connection: Upgrade\r\n"
                f"Sec-WebSocket-Accept: {accept_key}\r\n"
                "\r\n"
            )
            
            client_socket.send(response.encode())
            return True
        except Exception as e:
            print(f"Handshake error: {e}")
            try:
                client_socket.close()
            except:
                pass
            return None
    
    def _process_command(self, ws_conn, data):
        try:
            command = json.loads(data.decode('utf-8'))
            
            if not isinstance(command, dict):
                ws_conn.send_frame(json.dumps({"status": "error", "message": "Invalid command format"}))
                return
            
            action = command.get('action')
            if not action:
                ws_conn.send_frame(json.dumps({"status": "error", "message": "No action specified"}))
                return
            
            if action in self.command_handlers:
                result = self.command_handlers[action](command)
                ws_conn.send_frame(json.dumps(result))
            else:
                ws_conn.send_frame(json.dumps({"status": "error", "message": f"Unknown action: {action}"}))
        
        except json.JSONDecodeError:
            ws_conn.send_frame(json.dumps({"status": "error", "message": "Invalid JSON"}))
        except Exception as e:
            ws_conn.send_frame(json.dumps({"status": "error", "message": str(e)}))
    
    def _handle_client(self, ws_conn):
        while ws_conn.connected and self.running:
            try:
                opcode, payload = ws_conn.receive_frame()
                
                if opcode is None:
                    break
                
                if opcode == 0x08:
                    break
                
                elif opcode == 0x09:
                    ws_conn.send_frame(payload, 0x0A)
                
                elif opcode == 0x01:
                    self._process_command(ws_conn, payload)
                
                gc.collect()
                
            except Exception as e:
                print(f"Client handler error: {e}")
                break
        
        ws_conn.close()
        if ws_conn in self.clients:
            self.clients.remove(ws_conn)
    
    def start(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind(('0.0.0.0', self.port))
        self.server_socket.listen(self.max_connections)
        self.server_socket.setblocking(False)
        self.running = True
        
        print(f"WebSocket server started on port {self.port}")
    
    def accept_connections(self):
        try:
            client_socket, addr = self.server_socket.accept()
            client_socket.settimeout(30.0)
            
            print(f"Connection from {addr}")
            
            if self._handle_handshake(client_socket):
                ws_conn = WebSocketConnection(client_socket, addr)
                ws_conn.connected = True
                self.clients.append(ws_conn)
                
                client_socket.setblocking(False)
                return ws_conn
            
        except OSError:
            pass
        
        return None
    
    def process_clients(self):
        for ws_conn in self.clients[:]:
            try:
                opcode, payload = ws_conn.receive_frame()
                
                if opcode is None:
                    continue
                
                if opcode == 0x08:
                    ws_conn.close()
                    self.clients.remove(ws_conn)
                
                elif opcode == 0x09:
                    ws_conn.send_frame(payload, 0x0A)
                
                elif opcode == 0x01:
                    self._process_command(ws_conn, payload)
                
            except OSError:
                pass
            except Exception as e:
                print(f"Error processing client: {e}")
                ws_conn.close()
                if ws_conn in self.clients:
                    self.clients.remove(ws_conn)
        
        gc.collect()
    
    def broadcast(self, message):
        if isinstance(message, dict):
            message = json.dumps(message)
        
        for ws_conn in self.clients[:]:
            if not ws_conn.send_frame(message):
                ws_conn.close()
                self.clients.remove(ws_conn)
    
    def stop(self):
        self.running = False
        for ws_conn in self.clients[:]:
            ws_conn.close()
        self.clients.clear()
        if self.server_socket:
            self.server_socket.close()

class IoTDevice:
    def __init__(self):
        self.led = Pin(2, Pin.OUT)
        self.state = {"led": False, "uptime": 0}
        self.start_time = time.time()
    
    def turn_on(self, command):
        self.led.on()
        self.state["led"] = True
        return {"status": "success", "action": "turn_on", "state": self.state}
    
    def turn_off(self, command):
        self.led.off()
        self.state["led"] = False
        return {"status": "success", "action": "turn_off", "state": self.state}
    
    def toggle(self, command):
        self.state["led"] = not self.state["led"]
        if self.state["led"]:
            self.led.on()
        else:
            self.led.off()
        return {"status": "success", "action": "toggle", "state": self.state}
    
    def get_status(self, command):
        self.state["uptime"] = int(time.time() - self.start_time)
        return {"status": "success", "action": "get_status", "state": self.state}

def connect_wifi(ssid, password, timeout=10):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    
    if not wlan.isconnected():
        print(f'Connecting to {ssid}...')
        wlan.connect(ssid, password)
        
        start = time.time()
        while not wlan.isconnected():
            if time.time() - start > timeout:
                print('Connection timeout')
                return None
            time.sleep(0.5)
    
    print('Network connected')
    print('IP:', wlan.ifconfig()[0])
    return wlan.ifconfig()[0]

def main():
    WIFI_SSID = "YourWiFiSSID"
    WIFI_PASSWORD = "YourWiFiPassword"
    
    ip = connect_wifi(WIFI_SSID, WIFI_PASSWORD)
    if not ip:
        print("Failed to connect to WiFi")
        return
    
    device = IoTDevice()
    server = WebSocketServer(port=80, max_connections=5)
    
    server.register_handler("turn_on", device.turn_on)
    server.register_handler("turn_off", device.turn_off)
    server.register_handler("toggle", device.toggle)
    server.register_handler("get_status", device.get_status)
    
    server.start()
    
    print(f"WebSocket server running at ws://{ip}/")
    print("Waiting for connections...")
    
    last_status_broadcast = time.time()
    
    try:
        while True:
            new_conn = server.accept_connections()
            if new_conn:
                print(f"New WebSocket connection from {new_conn.addr}")
            
            server.process_clients()
            
            if time.time() - last_status_broadcast > 30:
                device.state["uptime"] = int(time.time() - device.start_time)
                server.broadcast({"type": "status_update", "state": device.state})
                last_status_broadcast = time.time()
            
            time.sleep(0.01)
    
    except KeyboardInterrupt:
        print("\nShutting down...")
        server.stop()

if __name__ == "__main__":
    main()